var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"평소 듣던 사이렌이랑 달라.","JPN":"いつもと音が違う。","ENG":"No, it's a different alarm from what I'm used to.","TWN":"和平時聽到的警報聲不一樣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이건 분명 최고 단계 경보일 텐데…?!","JPN":"これは確か、最高段階の警報のはず……！","ENG":"I think this is the highest alert...!","TWN":"這應該是最高等級的警報……？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>3종 침식체, 통칭 키키모라가 출몰했으니 민병단이 아닌 분들은 모두 대피하여 주십시오.</color>","JPN":"<color=#ffd34c>第3種侵食体、通称キキーモラが出現。民兵団以外の人は速やかに避難してください。</color>","ENG":"<color=#ffd34c>Category 3 C.O., A.K.A Kikimora has appeared. Everyone except the militia should evacuate the premises.</color>","TWN":"<color=#ffd34c>發現3類侵蝕體奇奇莫拉行蹤，請非民兵團成員全部撤離。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이건 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這不是演習。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>다시 한번 알려드립니다.</color>","JPN":"<color=#ffd34c>もう一度お知らせします……</color>","ENG":"<color=#ffd34c>I repeat.</color>","TWN":"<color=#ffd34c>重複，這不是演習。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>3종 침식체, 통칭 키키모라가 출몰했으며……</color>","JPN":"<color=#ffd34c>第3種侵食体、通称キキーモラが出現……</color>","ENG":"<color=#ffd34c>Category 3 C.O., A.K.A Kikimora has appeared...</color>","TWN":"<color=#ffd34c>發現3類侵蝕體奇奇莫拉行蹤……</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"3, 3종이라니?! 말도 안 돼!","JPN":"だ、第3種！？　そんな！","ENG":"A-a Category 3?! That can't be!","TWN":"3，3類？！不可能！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤! 어디 가는 거야?!","JPN":"サシャ！　どこに行くの！？","ENG":"Sasha! Where are you going?!","TWN":"莎夏！你去哪裡？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"당연히 싸우러 가야지!","JPN":"決まってるでしょう！　戦わないと！","ENG":"To fight, of course!","TWN":"當然是去戰鬥！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"3종은 만만한 개체가 아냐!","JPN":"第3種はそんな簡単に倒せる個体じゃない！","ENG":"But a Category 3 isn't something you can easily defeat on your own!","TWN":"3類可不是好對付的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"누가 혼자 싸운대?","JPN":"何も一人で戦うつもりはないよ！","ENG":"Who said anything about fighting alone?","TWN":"誰說要單獨戰鬥了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"전선에서 싸우는 건 무리겠지만… 분명 내가 할 수 있는 게 있을 거야.","JPN":"前線で戦うのは無理かもしれないけど……きっと私にできることがあるはず。","ENG":"I might not be fighting it in the forefront, but... I'm sure there's something I can do.","TWN":"雖然在前線戰鬥有些勉強……但我肯定能做點什麼。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"빨리… 고물들을 잔뜩 들고 가야 해!","JPN":"早く……古鉄をできるだけ運ばないと！","ENG":"C'mon...! We need to bring all the junk we can!","TWN":"快點……得帶上大量的破銅爛鐵！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"총기, 총알… 보급할 수 있는 건 뭐든 전부 만들어봐야겠어!","JPN":"銃、弾丸……役に立ちそうなものならとにかく何でも作る！","ENG":"Firearms, bullets... I'll make anything that can be helpful.","TWN":"槍支、子彈……能補給的全都得做出來！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이젠 아예 키키모라까지 나타났다고?","JPN":"ついにキキーモラが現れたの？","ENG":"A Kikimora is appearing now?","TWN":"連奇奇莫拉都出現了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"우리가 살던 곳을 쑥대밭으로 만든 녀석이 분명해.","JPN":"私たちの故郷をめちゃくちゃにしたやつに違いない。","ENG":"It's the same one that devastated our home.","TWN":"一定是毀了我們家園的那隻。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"확실하군. 그 녀석이 맞아.","JPN":"ああ、間違いない。","ENG":"I'm sure of it. It's that bastard.","TWN":"確定了，就是那個傢伙。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"그 자식만큼은 똑똑히 기억하고 있지!","JPN":"やつのことは昨日のことのように覚えてるぜ！","ENG":"I never forgot how that thing looked!","TWN":"那個傢伙我可是記得清清楚楚！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"하! 결국 끝장을 보겠다고 나타난 건가?","JPN":"はっ！　一人も残さないってことか？","ENG":"Ha! Has it finally shown up to finish what it started?","TWN":"哈！最終還是不肯放過我們嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"이거 이거, 대학살극이 펼쳐지겠구만!","JPN":"これはこれは、大量虐殺の始まりだな！","ENG":"I think... a massacre is about to go down here!","TWN":"這下好了，一場大屠殺要開始了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아니, 그렇지 않아!","JPN":"いや、違う！","ENG":"No, that won't happen!","TWN":"不，不會的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"녀석이 우리에게 죽으려고 직접 찾아와준 거다!","JPN":"やつが自ら殺されるためにやってきたんだ！","ENG":"It came back to die to us!","TWN":"那傢伙是來自投羅網的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"고생해서 찾을 수고를 덜었어. 오늘로 확실히 죽이겠다!","JPN":"おかげで捜す手間が省けたな。今日は確実に殺すぞ！","ENG":"It saved us the trouble of tracking it down. Today, we kill it for good!","TWN":"得來全不費工夫，今天一定要徹底幹掉它！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"확실히 죽는 건 우리 쪽일 확률이 더 높은 건 알고 있지?","JPN":"殺される可能性が高いのは私たちのほうってこと、わかってるわよね？","ENG":"You do know that the probability of us dying is higher, right?","TWN":"你知道的吧，我們這邊死的可能性更高。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"여차하면 당신이 도망칠 시간을 버는 데 최선을 다할게.","JPN":"いざとなったら、あなたが逃げる時間を稼ぐために全力を尽くす。","ENG":"I'll do my best to buy you enough time to escape if need be.","TWN":"如果情況不妙，我會盡全力讓你逃跑。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"헛소리할 시간에 저 녀석을 뭉갤 작전이나 짜!","JPN":"くだらないこと言ってないで、やつを潰す作戦を考えなさい！","ENG":"If you have time for that nonsense, come up with a plan to squash that thing!","TWN":"傻瓜，有這時間胡說八道，不如想個對付那傢伙的辦法！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"근질근질한 건 나도 마찬가지야. 당신과 죽던가 저 자식을 죽이던가!","JPN":"腕が鳴るのは私も同じよ。あなたと一緒に死ぬか、やつを殺すかの二択ね！","ENG":"I'm itching to kill it as much as you. I'll either kill that bastard or die with you trying!","TWN":"我也一樣等不及了，今天不是它死，就是我們死！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아저씨!","JPN":"アンドレイさん！","ENG":"Andrei!","TWN":"大叔！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤?! 방송 들었을 텐데!","JPN":"サシャ！？　放送を聞いてなかったのか！？","ENG":"Sasha?! Didn't you hear the broadcast?!","TWN":"莎夏？！你應該聽到廣播了吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"카운터가 침식체랑 싸우지 않으면 뭘 하라구요?!","JPN":"カウンタ―が侵食体と戦わずにどこに行けって言うんですか！","ENG":"But what else would a Counter do if not fighting C.O.s?!","TWN":"制裁者當然要和侵蝕體戰鬥！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마브카, 네가 끌고 나온 거냐?!","JPN":"マブカ、お前が連れてきたのか！？","ENG":"Mavka, did you bring her here?!","TWN":"瑪卡，是你帶她出來的嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아저씨도 사샤 고집이 얼마나 센지 잘 알잖아.","JPN":"サシャの頑固なところはアンドレイさんだって知ってるでしょう。","ENG":"You know how stubborn Sasha is.","TWN":"大叔，你也知道莎夏有多固執。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤는 걱정할 필요 없어. 녀석은 내가 상대할 거야.","JPN":"サシャのことは心配要らない。やつは私が相手する。","ENG":"But you have nothing to worry about her. I'll take it down.","TWN":"不用擔心莎夏，我會對付那個傢伙的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"바보야! 저게 우리 마을을 쑥대밭으로 만든 놈이야!","JPN":"バカ！　あいつが私の故郷をめちゃくちゃにしたのよ！","ENG":"You idiot! That thing is what destroyed our village!","TWN":"笨蛋！那傢伙就是毀掉我們家的那隻！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"아무리 북방군의 기술력이라도 맨손으로 저걸 상대할 수 있을 리가 없어!","JPN":"北方軍の技術力をもってしても、素手であんなやつに太刀打ちできるわけがない！","ENG":"Even with the Northern Army's technology, you can't defeat that with just your bare hands!","TWN":"就算是擁有先進技術的北方軍，也不可能徒手對付那個東西！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그건 해봐야 알겠지.","JPN":"できるかどうかはやってみないとね。","ENG":"I guess we'll find out.","TWN":"試一下就知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"어이! 언제까지 수다 떨고 있을 거야! 다 죽고 싶어?!","JPN":"おい！　いつまでお喋りしてるんだ！　皆殺されたいのか！？","ENG":"Hey! Are y'all done chatting over there?! Do y'all have a death wish or something?!","TWN":"喂！你們打算聊到什麼時候！不想活了嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L23_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"젠장!","JPN":"くそ！","ENG":"Dammit!","TWN":"該死！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤. 잘 들어.","JPN":"サシャ、よく聞いて。","ENG":"Sasha. Listen to me.","TWN":"莎夏。你聽好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"맨손으로 싸워야 하는 지금, 나도 3종은 버거운 상대야.","JPN":"素手でしか戦えない私にとって、第3種は難しい相手だ。","ENG":"A Category 3 is difficult for me to fight with no weapons.","TWN":"光憑雙手的話，我也很難對付3類的敵人。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"여차하면 너라도 도망가.","JPN":"いざとなったら、あなた一人でも逃げて。","ENG":"So if anything goes wrong, you have to run away.","TWN":"情況不妙的話，你就跑得遠遠的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그게 무슨 소리야!","JPN":"何言ってるの！","ENG":"What are you talking about?!","TWN":"你在說什麼！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"절대 도망치지 않을 거야. 우리라면 무조건 이길 수 있어!","JPN":"絶対逃げない。私たちならきっと勝てる！","ENG":"I'm never running away! The two of us can win against it!","TWN":"我絕對不會逃跑。我們一定能贏！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤……!","JPN":"サシャ……！","ENG":"Sasha...!","TWN":"莎夏……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"녀석이 온다!","JPN":"来るぞ！","ENG":"It's coming!","TWN":"那傢伙來了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};